def find_triples(max_val=50):
    solutions = set()
    for p in range(-max_val, max_val+1):
        for q in range(-max_val, max_val+1):
            for r in range(-max_val, max_val+1):
                if p==0 and q==0 and r==0:
                    continue
                values = set()
                for x in [0, 1]:
                    for y in [0, 1]:
                        for z in [0, 1]:
                            values.add(abs(p*x + q*y + r*z))
                if len(values) == 8:
                    sorted_vals = sorted(list(values))
                    if sorted_vals[0] == 0:
                        K = sorted_vals[1]
                        if K == 0: continue
                        valid = True
                        for i in range(1, 8):
                            if sorted_vals[i] != i * K:
                                valid = False
                                break
                        if valid:
                            a2 = (p**2 + q**2 + r**2) / (K**2)
                            solutions.add((p, q, r, K, a2))
    return solutions

sols = find_triples(50)
a2_values = sorted(set(s[4] for s in sols))
print("Unique a^2 values:", a2_values)
print("Number of unique a^2 values:", len(a2_values))
total_sum = sum(a2_values)
print("Sum of a^2 values:", total_sum)
